import{_ as l,o as r,c as t,ai as i}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"Java/Spring 开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/java-projects.md","filePath":"open-source/java-projects.md"}'),e={name:"open-source/java-projects.md"};function o(n,a,s,h,u,g){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="java-spring-开源项目" tabindex="-1">Java/Spring 开源项目 <a class="header-anchor" href="#java-spring-开源项目" aria-label="Permalink to “Java/Spring 开源项目”">​</a></h1><p>本页面精选了优秀的Java/Spring开源项目，包括Spring Boot应用、微服务框架、工具库等。</p><h2 id="spring-boot-应用框架" tabindex="-1">Spring Boot 应用框架 <a class="header-anchor" href="#spring-boot-应用框架" aria-label="Permalink to “Spring Boot 应用框架”">​</a></h2><h3 id="企业级应用" tabindex="-1">企业级应用 <a class="header-anchor" href="#企业级应用" aria-label="Permalink to “企业级应用”">​</a></h3><ul><li><p><strong>mall</strong>：完整的电商系统，包括前后台管理系统</p><ul><li>GitHub: <a href="https://github.com/macrozheng/mall" target="_blank" rel="noreferrer">https://github.com/macrozheng/mall</a></li><li>技术栈: Spring Boot + MyBatis + Redis + Elasticsearch</li><li>功能: 商品管理、订单处理、用户管理、支付集成</li></ul></li><li><p><strong>mall-swarm</strong>：微服务版本的电商系统</p><ul><li>GitHub: <a href="https://github.com/macrozheng/mall-swarm" target="_blank" rel="noreferrer">https://github.com/macrozheng/mall-swarm</a></li><li>技术栈: Spring Cloud + Nacos + Gateway + Docker</li><li>功能: 分布式电商系统，支持高并发</li></ul></li><li><p><strong>eladmin</strong>：基于Spring Boot的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/elunez/eladmin" target="_blank" rel="noreferrer">https://github.com/elunez/eladmin</a></li><li>技术栈: Spring Boot + Vue.js + MySQL + Redis</li><li>功能: 用户管理、权限控制、系统监控</li></ul></li></ul><h3 id="权限认证框架" tabindex="-1">权限认证框架 <a class="header-anchor" href="#权限认证框架" aria-label="Permalink to “权限认证框架”">​</a></h3><ul><li><p><strong>Sa-Token</strong>：轻量级Java权限认证框架</p><ul><li>GitHub: <a href="https://github.com/dromara/Sa-Token" target="_blank" rel="noreferrer">https://github.com/dromara/Sa-Token</a></li><li>功能: 登录认证、权限验证、会话管理</li><li>特点: 简单易用，支持分布式</li></ul></li><li><p><strong>Spring Security</strong>：官方安全框架</p><ul><li>GitHub: <a href="https://github.com/spring-projects/spring-security" target="_blank" rel="noreferrer">https://github.com/spring-projects/spring-security</a></li><li>功能: 身份认证、授权、防护攻击</li></ul></li></ul><h3 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h3><ul><li><p><strong>Hutool</strong>：Java工具类库</p><ul><li>GitHub: <a href="https://github.com/dromara/hutool" target="_blank" rel="noreferrer">https://github.com/dromara/hutool</a></li><li>功能: 日期处理、HTTP客户端、加密解密等</li></ul></li><li><p><strong>Apache Commons</strong>：Apache通用工具库</p><ul><li>GitHub: <a href="https://github.com/apache/commons-lang" target="_blank" rel="noreferrer">https://github.com/apache/commons-lang</a></li><li>功能: 字符串处理、集合操作、IO工具</li></ul></li></ul><h2 id="微服务框架" tabindex="-1">微服务框架 <a class="header-anchor" href="#微服务框架" aria-label="Permalink to “微服务框架”">​</a></h2><h3 id="spring-cloud-生态" tabindex="-1">Spring Cloud 生态 <a class="header-anchor" href="#spring-cloud-生态" aria-label="Permalink to “Spring Cloud 生态”">​</a></h3><ul><li><p><strong>Spring Cloud Alibaba</strong>：阿里微服务解决方案</p><ul><li>GitHub: <a href="https://github.com/alibaba/spring-cloud-alibaba" target="_blank" rel="noreferrer">https://github.com/alibaba/spring-cloud-alibaba</a></li><li>组件: Nacos、Sentinel、Seata等</li></ul></li><li><p><strong>Spring Cloud Netflix</strong>：Netflix微服务组件</p><ul><li>GitHub: <a href="https://github.com/spring-cloud/spring-cloud-netflix" target="_blank" rel="noreferrer">https://github.com/spring-cloud/spring-cloud-netflix</a></li><li>组件: Eureka、Ribbon、Hystrix等</li></ul></li></ul><h3 id="服务治理" tabindex="-1">服务治理 <a class="header-anchor" href="#服务治理" aria-label="Permalink to “服务治理”">​</a></h3><ul><li><p><strong>Nacos</strong>：服务发现和配置管理</p><ul><li>GitHub: <a href="https://github.com/alibaba/nacos" target="_blank" rel="noreferrer">https://github.com/alibaba/nacos</a></li><li>功能: 服务注册发现、配置中心、DNS服务</li></ul></li><li><p><strong>Sentinel</strong>：流量控制和熔断降级</p><ul><li>GitHub: <a href="https://github.com/alibaba/Sentinel" target="_blank" rel="noreferrer">https://github.com/alibaba/Sentinel</a></li><li>功能: 限流、熔断、系统负载保护</li></ul></li></ul><h2 id="数据访问层" tabindex="-1">数据访问层 <a class="header-anchor" href="#数据访问层" aria-label="Permalink to “数据访问层”">​</a></h2><h3 id="orm框架" tabindex="-1">ORM框架 <a class="header-anchor" href="#orm框架" aria-label="Permalink to “ORM框架”">​</a></h3><ul><li><p><strong>MyBatis</strong>：优秀的持久层框架</p><ul><li>GitHub: <a href="https://github.com/mybatis/mybatis-3" target="_blank" rel="noreferrer">https://github.com/mybatis/mybatis-3</a></li><li>特点: SQL映射、动态SQL、插件机制</li></ul></li><li><p><strong>MyBatis-Plus</strong>：MyBatis增强工具</p><ul><li>GitHub: <a href="https://github.com/baomidou/mybatis-plus" target="_blank" rel="noreferrer">https://github.com/baomidou/mybatis-plus</a></li><li>功能: 代码生成器、通用CRUD、分页插件</li></ul></li><li><p><strong>Hibernate</strong>：全功能ORM框架</p><ul><li>GitHub: <a href="https://github.com/hibernate/hibernate-orm" target="_blank" rel="noreferrer">https://github.com/hibernate/hibernate-orm</a></li><li>特点: JPA实现、对象关系映射</li></ul></li></ul><h2 id="测试框架" tabindex="-1">测试框架 <a class="header-anchor" href="#测试框架" aria-label="Permalink to “测试框架”">​</a></h2><ul><li><p><strong>JUnit 5</strong>：Java单元测试框架</p><ul><li>GitHub: <a href="https://github.com/junit-team/junit5" target="_blank" rel="noreferrer">https://github.com/junit-team/junit5</a></li><li>功能: 单元测试、集成测试</li></ul></li><li><p><strong>TestNG</strong>：下一代测试框架</p><ul><li>GitHub: <a href="https://github.com/testng-team/testng" target="_blank" rel="noreferrer">https://github.com/testng-team/testng</a></li><li>功能: 并行测试、数据驱动测试</li></ul></li></ul><h2 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h2><ul><li><p><strong>Maven</strong>：项目管理和构建工具</p><ul><li>GitHub: <a href="https://github.com/apache/maven" target="_blank" rel="noreferrer">https://github.com/apache/maven</a></li><li>功能: 依赖管理、项目构建</li></ul></li><li><p><strong>Gradle</strong>：现代构建工具</p><ul><li>GitHub: <a href="https://github.com/gradle/gradle" target="_blank" rel="noreferrer">https://github.com/gradle/gradle</a></li><li>特点: Groovy/Kotlin DSL、增量构建</li></ul></li></ul>',21)])])}const c=l(e,[["render",o]]);export{b as __pageData,c as default};
